  onLearnMore: () => void;
  onSignIn: () => void;
}

export function SignedOutShell({ onSignIn, onLearnMore }: SignedOutShellProps) {
  return (
    <div className="auth-gate">
      <div aria-hidden="true" className="auth-gate__titlebar-drag" />
      <div className="auth-gate__content">
